const events=Array.isArray(data.events)?data.events:[];
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Timeline';
const formatDate=(value) => {
  if(value===null||value===undefined||value==='') return 'Date TBD';
  const raw=String(value); const iso=/^\d{4}-\d{2}-\d{2}$/.test(raw); const parsed=new Date(iso?raw+'T00:00:00Z':raw);
  if(Number.isNaN(parsed.getTime())) return raw;
  return new Intl.DateTimeFormat(undefined,{month:'short',day:'numeric',year:'numeric',timeZone:iso?'UTC':undefined}).format(parsed);
};
const labels={done:'✓ Done',current:'● Current','at-risk':'Partial · at risk',issue:'✗ Issue',upcoming:'Upcoming'};
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','Vertical timeline')); heading.appendChild(make('h2','',title));
heading.appendChild(make('div','meta',data.subtitle?String(data.subtitle):(events.length+' dated event'+(events.length===1?'':'s')))); frame.appendChild(heading);
if(!events.length){
  frame.appendChild(make('div','empty','Add dated events to build the timeline.'));
}else{
  const list=make('div','list');
  events.forEach((event) => {
    const allowed=['done','current','at-risk','issue','upcoming']; const status=allowed.includes(event&&event.status)?event.status:'upcoming';
    const row=make('article','event '+status);
    const date=make('time','date'); if(event&&event.date) date.dateTime=String(event.date); date.appendChild(make('strong','',formatDate(event&&event.date)));
    if(event&&event.endDate) date.appendChild(make('span','', 'to '+formatDate(event.endDate))); row.appendChild(date);
    const rail=make('div','rail'); rail.setAttribute('aria-hidden','true'); rail.appendChild(make('span','dot')); row.appendChild(rail);
    const card=make('div','card'); const cardTop=make('div','card-top'); const titleWrap=make('div','title-wrap');
    if(event&&event.icon) titleWrap.appendChild(make('span','icon',String(event.icon)));
    titleWrap.appendChild(make('h3','',event&&event.title!=null?String(event.title):'Untitled event')); cardTop.appendChild(titleWrap);
    cardTop.appendChild(make('span','pill '+status,labels[status])); card.appendChild(cardTop);
    if(event&&event.description) card.appendChild(make('p','description',String(event.description)));
    const meta=event&&Array.isArray(event.meta)?event.meta:[];
    if(meta.length){ const tags=make('div','tags'); meta.forEach((value) => tags.appendChild(make('span','tag',String(value)))); card.appendChild(tags); }
    row.appendChild(card); list.appendChild(row);
  });
  frame.appendChild(list);
}
root.appendChild(frame);
parent.appendChild(host);
